constructor(
  status: ErrorSchemaType['status'],
  type: ErrorKey,
  severity: ErrorSchemaType['severity'],
  opts?: AppErrorOpts,
) {
  const i18nOpts = { ns: ['appError', 'error'], defaultValue: opts?.name ?? 'Unknown error' };
  const messageFallback = opts?.message ?? i18n.t(type, i18nOpts);
  super(i18n.t(`${type}.text`, { ...i18nOpts, defaultValue: messageFallback }));

  this.name = opts?.name ?? i18n.t(type, { ...i18nOpts, defaultValue: 'ApiError' });
  this.status = status;
  this.type = type;
  this.entityType = opts?.entityType;
  this.severity = severity;
  this.willRedirect = opts?.willRedirect ?? false;
  this.meta = opts?.meta;
  this.stack = opts?.originalError?.stack ?? this.stack;
  this.cause = opts?.originalError?.cause;
}

function getUploadTokenOp(ctx: AuthContext, { isPublic, organizationId, templateId }: GetUploadTokenOpts) {
  const user = ctx.var.user;

  const sub = [organizationId, user.id].filter((part): part is string => typeof part === 'string').join('/');

  if (!env.TRANSLOADIT_KEY || !env.TRANSLOADIT_SECRET) {
    return { sub, public: isPublic, s3: !!env.S3_ACCESS_KEY_ID, params: null, signature: null };
  }

  try {
    const params = getParams(templateId, isPublic, sub);
    const paramsString = JSON.stringify(params);
    const signature = getSignature(paramsString);
    return { sub, public: isPublic, s3: !!env.S3_ACCESS_KEY_ID, params, signature };
  } catch (error) {
    if (error instanceof AppError) throw error;
    throw new AppError(500, 'auth_key_not_found', 'error', {
      ...(error instanceof Error ? { originalError: error } : {}),
    });
  }
}

removeNode = (node: Node): void => {
  if (!isNodeString(node)) {
    node[DOM_STASH]?.[1][STASH_EFFECT]?.forEach((data: EffectData) => data[2]?.())

    refCleanupMap.get(node.e as Element)?.()
    if (node.p === 2) {
      node.vC?.forEach((n) => (n.p = 2))
    }
    node.vC?.forEach(removeNode)
  }
  if (!node.p) {
    node.e?.remove()
    delete node.e
  }
  if (typeof node.tag === 'function') {
    updateMap.delete(node)
    fallbackUpdateFnArrayMap.delete(node)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    delete (node as any)[DOM_STASH][3] // delete explicitly for avoid circular reference
    node.a = true
  }
}

isValidStylePropertyName = (name: string): boolean => {
  if (validStylePropertyNameCache.has(name)) {
    return true
  }
  const len = name.length
  if (len === 0) {
    return false
  }
  for (let i = 0; i < len; i++) {
    const c = name.charCodeAt(i)
    if (
      !(
        (c >= 0x61 && c <= 0x7a) || // a-z
        (c >= 0x41 && c <= 0x5a) || // A-Z
        (c >= 0x30 && c <= 0x39) || // 0-9
        c === 0x2d || // -
        c === 0x5f // _
      )
    ) {
      // non-fast-path character found — fall back to regex for the full name
      if (!invalidStylePropertyNameCharRe.test(name)) {
        cacheValidName(validStylePropertyNameCache, validStylePropertyNameCacheMax, name)
        return true
      } else {
        return false
      }
    }
  }
  cacheValidName(validStylePropertyNameCache, validStylePropertyNameCacheMax, name)
  return true
}

trimTrailingSlash = (options?: TrimTrailingSlashOptions): MiddlewareHandler => {
  return async function trimTrailingSlash(c, next) {
    if (options?.alwaysRedirect) {
      if (
        (c.req.method === 'GET' || c.req.method === 'HEAD') &&
        c.req.path !== '/' &&
        c.req.path.at(-1) === '/'
      ) {
        const url = new URL(c.req.url)
        url.pathname = url.pathname.substring(0, url.pathname.length - 1)

        return c.redirect(url.toString(), 301)
      }
    }

    await next()

    if (
      !options?.alwaysRedirect &&
      c.res.status === 404 &&
      (c.req.method === 'GET' || c.req.method === 'HEAD') &&
      c.req.path !== '/' &&
      c.req.path.at(-1) === '/'
    ) {
      const url = new URL(c.req.url)
      url.pathname = url.pathname.substring(0, url.pathname.length - 1)

      c.res = c.redirect(url.toString(), 301)
    }
  }
}

appendTrailingSlash = (options?: AppendTrailingSlashOptions): MiddlewareHandler => {
  return async function appendTrailingSlash(c, next) {
    if (options?.alwaysRedirect) {
      if (
        (c.req.method === 'GET' || c.req.method === 'HEAD') &&
        c.req.path.at(-1) !== '/' &&
        !options.skip?.(c.req.path)
      ) {
        const url = new URL(c.req.url)
        url.pathname += '/'

        return c.redirect(url.toString(), 301)
      }
    }

    await next()

    if (
      !options?.alwaysRedirect &&
      c.res.status === 404 &&
      (c.req.method === 'GET' || c.req.method === 'HEAD') &&
      c.req.path.at(-1) !== '/' &&
      !options?.skip?.(c.req.path)
    ) {
      const url = new URL(c.req.url)
      url.pathname += '/'

      c.res = c.redirect(url.toString(), 301)
    }
  }
}

function compareKey(a: string, b: string): number {
  if (a.length === 1) {
    return b.length === 1 ? (a < b ? -1 : 1) : -1
  }
  if (b.length === 1) {
    return 1
  }

  // wildcard
  if (a === ONLY_WILDCARD_REG_EXP_STR || a === TAIL_WILDCARD_REG_EXP_STR) {
    return 1
  } else if (b === ONLY_WILDCARD_REG_EXP_STR || b === TAIL_WILDCARD_REG_EXP_STR) {
    return -1
  }

  // label
  if (a === LABEL_REG_EXP_STR) {
    return 1
  } else if (b === LABEL_REG_EXP_STR) {
    return -1
  }

  return a.length === b.length ? (a < b ? -1 : 1) : b.length - a.length
}

buildRegExpStr(): string {
  const childKeys = Object.keys(this.#children).sort(compareKey)

  const strList = childKeys.map((k) => {
    const c = this.#children[k]
    return (
      (typeof c.#varIndex === 'number'
        ? `(${k})@${c.#varIndex}`
        : regExpMetaChars.has(k)
          ? `\\${k}`
          : k) + c.buildRegExpStr()
    )
  })

  if (typeof this.#index === 'number') {
    strList.unshift(`#${this.#index}`)
  }

  if (strList.length === 0) {
    return ''
  }
  if (strList.length === 1) {
    return strList[0]
  }

  return '(?:' + strList.join('|') + ')'
}

#buildMatcher(method: string): Matcher<T> | null {
  const routes: [string, HandlerWithMetadata<T>[]][] = []

  let hasOwnRoute = method === METHOD_NAME_ALL

  ;[this.#middleware!, this.#routes!].forEach((r) => {
    const ownRoute = r[method]
      ? Object.keys(r[method]).map((path) => [path, r[method][path]])
      : []
    if (ownRoute.length !== 0) {
      hasOwnRoute ||= true
      routes.push(...(ownRoute as [string, HandlerWithMetadata<T>[]][]))
    } else if (method !== METHOD_NAME_ALL) {
      routes.push(
        ...(Object.keys(r[METHOD_NAME_ALL]).map((path) => [path, r[METHOD_NAME_ALL][path]]) as [
          string,
          HandlerWithMetadata<T>[],
        ][])
      )
    }
  })

  if (!hasOwnRoute) {
    return null
  } else {
    return buildMatcherFromPreprocessedRoutes(routes)
  }
}

function generateToken(payload: { userId: number; username: string }): string {
  const tokenPayload = {
    ...payload,
    exp: Date.now() + TOKEN_EXPIRY
  }

  const header = {
    alg: 'HS256',
    typ: 'JWT'
  }

  const encodedHeader = base64UrlEncode(JSON.stringify(header))
  const encodedPayload = base64UrlEncode(JSON.stringify(tokenPayload))
  const signature = CryptoJS.HmacSHA256(`${encodedHeader}.${encodedPayload}`, JWT_SECRET).toString()
  const encodedSignature = base64UrlEncode(signature)

  return `${encodedHeader}.${encodedPayload}.${encodedSignature}`
}

function resolver<Schema extends StandardSchemaV1>(
  schema: Schema,
  userDefinedOptions?: Record<string, unknown>,
) {
  const vendor = schema["~standard"].vendor;

  return {
    vendor,
    validate: schema["~standard"].validate,
    toJSONSchema: (customOptions?: Record<string, unknown>) =>
      toJsonSchema(schema, { ...userDefinedOptions, ...customOptions }) as
        | JSONSchema7
        | Promise<JSONSchema7>,
    toOpenAPISchema: (customOptions?: Record<string, unknown>) =>
      toOpenAPISchema(schema, {
        ...userDefinedOptions,
        ...customOptions,
        ...(vendor === "arktype"
          ? injectArktypeFallback(userDefinedOptions, customOptions)
          : undefined),
        ...(vendor === "zod"
          ? injectZodV4DateOverride(schema, userDefinedOptions, customOptions)
          : undefined),
      }),
  };
}
